  1→export type OpenRouterReasoningEffort = "xhigh" | "high" | "medium" | "low" | "minimal" | "none";
  2→
  3→export type OpenRouterReasoningOptions = {
  4→  enabled?: boolean;
  5→  exclude?: boolean;
  6→  max_tokens?: number;
  7→  effort?: OpenRouterReasoningEffort;
  8→};
  9→
 10→export type ServerConfig = {
 11→  openRouterApiKey: string;
 12→  assistantModelId: string;
 13→  extractionModelId: string;
 14→  pmModelId: string;
 15→  embeddingModelId: string;
 16→  embeddingDimension: number;
 17→  extractionStoreThreshold: number;
 18→  extractionDisplayThreshold: number;
 19→  openRouterReasoning?: OpenRouterReasoningOptions;
 20→  surrealUrl: string;
 21→  surrealUsername: string;
 22→  surrealPassword: string;
 23→  surrealNamespace: string;
 24→  surrealDatabase: string;
 25→  port: number;
 26→  githubWebhookSecret?: string;
 27→};
 28→
 29→export function loadServerConfig(): ServerConfig {
 30→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 31→
 32→  const extractionStoreThreshold = parseUnitInterval(
 33→    requireEnv("EXTRACTION_STORE_THRESHOLD"),
 34→    "EXTRACTION_STORE_THRESHOLD",
 35→  );
 36→
 37→  const extractionDisplayThreshold = parseUnitInterval(
 38→    requireEnv("EXTRACTION_DISPLAY_THRESHOLD"),
 39→    "EXTRACTION_DISPLAY_THRESHOLD",
 40→  );
 41→
 42→  if (extractionDisplayThreshold < extractionStoreThreshold) {
 43→    throw new Error("EXTRACTION_DISPLAY_THRESHOLD must be greater than or equal to EXTRACTION_STORE_THRESHOLD");
 44→  }
 45→
 46→  const assistantModelId = requireEnv("ASSISTANT_MODEL");
 47→  const extractionModelId = requireEnv("EXTRACTION_MODEL");
 48→  const pmModelId = Bun.env.PM_MODEL && Bun.env.PM_MODEL.trim().length > 0
 49→    ? Bun.env.PM_MODEL.trim()
 50→    : extractionModelId;
 51→  const embeddingModelId = requireEnv("OPENROUTER_EMBEDDING_MODEL");
 52→  const embeddingDimension = parsePositiveInteger(requireEnv("EMBEDDING_DIMENSION"), "EMBEDDING_DIMENSION");
 53→
 54→  const surrealUrl = requireEnv("SURREAL_URL");
 55→  const surrealUsername = requireEnv("SURREAL_USERNAME");
 56→  const surrealPassword = requireEnv("SURREAL_PASSWORD");
 57→  const surrealNamespace = requireEnv("SURREAL_NAMESPACE");
 58→  const surrealDatabase = requireEnv("SURREAL_DATABASE");
 59→
 60→  const port = parsePositiveInteger(requireEnv("PORT"), "PORT");
 61→  const githubWebhookSecret = Bun.env.GITHUB_WEBHOOK_SECRET?.trim() || undefined;
 62→
 63→  return {
 64→    openRouterApiKey,
 65→    assistantModelId,
 66→    extractionModelId,
 67→    pmModelId,
 68→    embeddingModelId,
 69→    embeddingDimension,
 70→    extractionStoreThreshold,
 71→    extractionDisplayThreshold,
 72→    openRouterReasoning: parseOpenRouterReasoning(),
 73→    surrealUrl,
 74→    surrealUsername,
 75→    surrealPassword,
 76→    surrealNamespace,
 77→    surrealDatabase,
 78→    port,
 79→    ...(githubWebhookSecret ? { githubWebhookSecret } : {}),
 80→  };
 81→}
 82→
 83→function requireEnv(name: string): string {
 84→  const value = Bun.env[name];
 85→  if (!value || value.trim().length === 0) {
 86→    throw new Error(`${name} is required`);
 87→  }
 88→
 89→  return value;
 90→}
 91→
 92→function parsePositiveInteger(value: string, envName: string): number {
 93→  const parsed = Number(value);
 94→  if (!Number.isInteger(parsed) || parsed < 1) {
 95→    throw new Error(`${envName} must be a positive integer`);
 96→  }
 97→  return parsed;
 98→}
 99→
100→function parseUnitInterval(value: string, envName: string): number {
101→  const parsed = Number(value);
102→  if (!Number.isFinite(parsed) || parsed < 0 || parsed > 1) {
103→    throw new Error(`${envName} must be a number between 0 and 1`);
104→  }
105→
106→  return parsed;
107→}
108→
109→function parseOpenRouterReasoning(): OpenRouterReasoningOptions | undefined {
110→  const effortValue = Bun.env.OPENROUTER_REASONING_EFFORT;
111→  const maxTokensValue = Bun.env.OPENROUTER_REASONING_MAX_TOKENS;
112→
113→  if (!effortValue && !maxTokensValue) {
114→    return undefined;
115→  }
116→
117→  const reasoning: OpenRouterReasoningOptions = {};
118→
119→  if (effortValue) {
120→    const allowedEfforts: OpenRouterReasoningEffort[] = ["xhigh", "high", "medium", "low", "minimal", "none"];
121→
122→    if (!allowedEfforts.includes(effortValue as OpenRouterReasoningEffort)) {
123→      throw new Error("OPENROUTER_REASONING_EFFORT must be one of xhigh, high, medium, low, minimal, none");
124→    }
125→    reasoning.effort = effortValue as OpenRouterReasoningEffort;
126→  }
127→
128→  if (maxTokensValue) {
129→    const parsed = Number(maxTokensValue);
130→    if (!Number.isFinite(parsed) || parsed < 1) {
131→      throw new Error("OPENROUTER_REASONING_MAX_TOKENS must be a positive number");
132→    }
133→    reasoning.max_tokens = parsed;
134→  }
135→
136→  return reasoning;
137→}
