 75→    const hasSarahNode = peopleAfterUnknown.some((person) => normalizeName(person.name) === "sarah");
 76→    expect(hasSarahNode).toBe(false);
 77→    expect(peopleAfterUnknown.length).toBe(initialPeople.length);
 78→
 79→    const knownPersonEvents = await sendChatAndCollectEvents(baseUrl, {
 80→      workspaceId: create.workspaceId,
 81→      conversationId: create.conversationId,
 82→      text: "Marcus decided to use SurrealDB for graph persistence.",
 83→    });
